import { Component, EventEmitter, Input, Output } from '@angular/core';
import { ResumeTemplate } from '../../../core/models/resume.model';

@Component({
  selector: 'app-template-card',
  templateUrl: './template-card.component.html'
})
export class TemplateCardComponent {
  @Input() template!: ResumeTemplate;
  @Input() atsScore = 92;
  @Input() usedCountLabel = '10,000+ students';
  @Input() favorite = false;
  @Output() preview = new EventEmitter<ResumeTemplate>();
  @Output() useTemplate = new EventEmitter<ResumeTemplate>();
  @Output() toggleFavorite = new EventEmitter<ResumeTemplate>();

  get tags(): string[] {
    try {
      const parsed = JSON.parse(this.template.tagsJson);
      return Array.isArray(parsed) ? parsed : [];
    } catch {
      return [];
    }
  }

  onPreview(): void {
    this.preview.emit(this.template);
  }

  onUseTemplate(): void {
    this.useTemplate.emit(this.template);
  }

  onToggleFavorite(): void {
    this.toggleFavorite.emit(this.template);
  }
}
<article class="shell-card overflow-hidden p-4">
  <div class="overflow-hidden rounded-[24px] bg-[#f8f9ff]">
    <img [src]="template.previewImageUrl" [alt]="template.name" class="h-[320px] w-full object-cover object-top">
  </div>
  <div class="p-4">
    <div class="flex items-start justify-between gap-3">
      <div>
        <h3 class="text-xl font-extrabold text-[#17172b]">{{ template.name }}</h3>
        <p class="mt-2 text-sm text-[#667085]">{{ template.category }} · {{ template.layoutType }}</p>
      </div>
      <button
        type="button"
        class="flex h-10 w-10 items-center justify-center rounded-full border border-[#d7dcff] bg-white text-lg transition hover:border-[#5b5cf0] hover:text-[#5b5cf0]"
        [attr.aria-pressed]="favorite"
        (click)="onToggleFavorite()">
        {{ favorite ? '♥' : '♡' }}
      </button>
    </div>

    <div class="mt-4 flex flex-wrap gap-2">
      <span *ngIf="template.atsFriendly" class="rounded-full bg-[#ecfdf3] px-3 py-1.5 text-xs font-bold text-[#16a34a]">ATS Friendly</span>
      <span class="rounded-full px-3 py-1.5 text-xs font-bold"
            [ngClass]="template.premium ? 'bg-[#fff0f0] text-[#ef4444]' : 'bg-[#ecfdf3] text-[#16a34a]'">
        {{ template.premium ? 'Premium' : 'Free' }}
      </span>
      <span *ngFor="let tag of tags | slice:0:3" class="rounded-full bg-[#edf2ff] px-3 py-1.5 text-xs font-semibold text-[#5b5cf0]">{{ tag }}</span>
    </div>

    <div class="mt-4 grid gap-2 text-sm text-[#667085]">
      <div>ATS Score: <span class="font-semibold text-[#17172b]">{{ atsScore }}/100</span></div>
      <div>Best for {{ template.roleType }}</div>
      <div>Used by {{ usedCountLabel }}</div>
    </div>

    <div class="mt-5 flex gap-3">
      <button type="button" class="btn-secondary text-sm" (click)="onPreview()">Preview</button>
      <button type="button" class="btn-primary flex-1 text-sm" (click)="onUseTemplate()">Use Template</button>
    </div>
  </div>
</article>
